const result = $input.first().json;
const runId = result.run_id;
const lastHwm = result.last_hwm;

// Calculate cutoff: use high water mark or fallback to 2 hours ago
const fallbackHours = 2;
let cutoff;
if (lastHwm) {
  cutoff = lastHwm;
} else {
  const d = new Date();
  d.setHours(d.getHours() - fallbackHours);
  cutoff = d.toISOString();
}

console.log('Run ID:', runId);
console.log('Last HWM:', lastHwm);
console.log('Using cutoff:', cutoff);

return [{ json: { run_id: runId, cutoff: cutoff, start_time: new Date().toISOString() } }];

// Get data from each step in the chain
// Each HTTP node passes through its response, and we can access prior nodes via $()
const prepData = $('Prepare Reconciliation').first().json;
const paperlessResponse = $('Fetch All Paperless Documents').first().json;
const tagsResponse = $('Fetch All Tags').first().json;
const qdrantResponse = $('Fetch All Qdrant Documents').first().json;

// Build tag ID → name mapping
const tagMap = {};
(tagsResponse.results || []).forEach(t => {
  tagMap[t.id] = t.name.toLowerCase();
});

// System tags to exclude when determining family
const SYSTEM_TAGS = ['inbox', 'intake', 'processed', 'processing', 'error', 'pending', 'ai_ready', 'ingestion_error'];

// Extract Paperless documents with their family (first non-system tag)
const paperlessDocs = (paperlessResponse.results || []).map(d => {
  const familyTag = (d.tags || []).map(tid => tagMap[tid]).filter(t => t && !SYSTEM_TAGS.includes(t))[0] || null;
  return {
    id: String(d.id),
    title: d.title,
    modified: d.modified,
    family_id: familyTag
  };
});
const paperlessIds = new Set(paperlessDocs.map(d => d.id));
const paperlessFamilyMap = {};
paperlessDocs.forEach(d => { paperlessFamilyMap[d.id] = d.family_id; });

// Extract unique document IDs and family_ids from Qdrant
const qdrantPoints = qdrantResponse.result?.points || [];
const qdrantDocIds = new Set();
const qdrantFamilyMap = {};
qdrantPoints.forEach(p => {
  if (p.payload?.document_id) {
    const docId = String(p.payload.document_id);
    qdrantDocIds.add(docId);
    if (!qdrantFamilyMap[docId]) {
      qdrantFamilyMap[docId] = p.payload.family_id || null;
    }
  }
});

console.log('Paperless docs:', paperlessIds.size);
console.log('Qdrant doc IDs:', qdrantDocIds.size);

// Find orphans (in Qdrant but not in Paperless)
const orphans = [];
qdrantDocIds.forEach(id => {
  if (!paperlessIds.has(id)) {
    orphans.push({ document_id: id, action: 'delete' });
  }
});

// Find missing (in Paperless but not in Qdrant)
const missing = [];
paperlessDocs.forEach(doc => {
  if (!qdrantDocIds.has(doc.id)) {
    missing.push({ document_id: doc.id, title: doc.title, action: 'ingest' });
  }
});

// Find family_id mismatches (in both, but family_id differs)
const mismatches = [];
qdrantDocIds.forEach(docId => {
  if (paperlessIds.has(docId)) {
    const expectedFamily = paperlessFamilyMap[docId];
    const actualFamily = qdrantFamilyMap[docId];
    if (expectedFamily && actualFamily && expectedFamily !== actualFamily) {
      const doc = paperlessDocs.find(d => d.id === docId);
      mismatches.push({
        document_id: docId,
        old_family_id: actualFamily,
        new_family_id: expectedFamily,
        title: doc?.title || 'Unknown'
      });
    }
  }
});

console.log('Orphans to delete:', orphans.length);
console.log('Missing to ingest:', missing.length);
console.log('Family mismatches:', mismatches.length);

return [{ json: {
  run_id: prepData.run_id,
  start_time: prepData.start_time,
  paperless_count: paperlessIds.size,
  qdrant_count: qdrantDocIds.size,
  orphans: orphans,
  missing: missing,
  mismatches: mismatches
}}];

// Merge results from all branches
const compareData = $('Compare Document Sets').first().json;
const runId = compareData.run_id;
const startTime = compareData.start_time;
const orphanCount = compareData.orphans.length;
const missingCount = compareData.missing.length;
const mismatchCount = compareData.mismatches.length;
const totalChecked = compareData.paperless_count;

return [{ json: {
  run_id: runId,
  start_time: startTime,
  documents_checked: totalChecked,
  documents_deleted: orphanCount,
  documents_ingested: missingCount,
  documents_family_updated: mismatchCount
}}];
